#include<bits/stdc++.h>
using namespace std;
int n,m,k,mod;
bool vis[100010],vis1[100010][55];
int dis[100010],flag,f[100010][55];
vector<pair<int,int>> mp[100010],mp1[100010];
void dijkstra(int st)
{
    priority_queue<pair<int,int>> q;
    q.push({0,st});
    memset(dis,0x3f,sizeof(dis));
    dis[st]=0;
    memset(vis,0,sizeof(vis));
    while(!q.empty())
    {
        int t=q.top().second;
        q.pop();
        if(vis[t])
        {
            continue;
        }
        vis[t]=true;
        for(auto i:mp1[t])
        {
            int v=i.first,val=i.second;
            if(dis[v]>dis[t]+val)
            {
                dis[v]=dis[t]+val;
                q.push({-dis[v],v});
            }
        }
    }
}
int dfs(int x,int d)
{
    if(flag)
    {
        return 0;
    }
    if(d>k)
    {
        return 0;
    }
    if(vis1[x][d])
    {
        flag=1;
        return 0;
    }
    if(f[x][d]!=-1)
    {
        return f[x][d];
    }
    f[x][d]=0;
    if(x==n)
    {
        f[x][d]++;
    }
    vis1[x][d]=true;
    for(auto i:mp[x])
    {
        int v=i.first,val=i.second;
        val+=dis[v]-dis[x];
        f[x][d]+=dfs(v,d+val);
        f[x][d]%=mod;
        if(flag)
        {
            return 0;
        }
    }
    vis1[x][d]=false;
    return f[x][d];
}
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        memset(f,-1,sizeof(f));
        memset(vis1,0,sizeof(vis1));
        scanf("%d%d%d%d",&n,&m,&k,&mod);
        for(int i=1;i<=n;i++)
        {
            mp[i].clear();
            mp1[i].clear();
        }
        for(int i=1;i<=m;i++)
        {
            int u,v,w;
            scanf("%d%d%d",&u,&v,&w);
            mp[u].push_back(make_pair(v,w));
            mp1[v].push_back(make_pair(u,w));
        }
        dijkstra(n);
        flag=0;
        dfs(1,0);
        if(flag)
        {
            printf("-1\n");
        }
        else
        {
            printf("%d\n",f[1][0]);
        }
    }
    return 0;
}
